        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.tetromino['x'] -= 1
                elif event.key == pygame.K_RIGHT:
                    self.tetromino['x'] += 1
                elif event.key == pygame.K_DOWN:
                    self.tetromino['y'] += 1
                elif event.key == pygame.K_UP:
                    self.tetromino['y'] -= 1
                elif event.key == pygame.K_SPACE:
                    self.drop_tetromino()
                elif event.key == pygame.K_TAB:
                    self.current_player = (self.current_player + 1) % 3

    def drop_tetromino(self):
        while self.is_valid_position(self.tetromino['x'], self.tetromino['y'] + 1):
            self.tetromino['y'] += 1
        self.lock_tetromino()
        self.clear_rows()
        self.tetromino = self.generate_tetromino()

    def is_valid_position(self, x, y):
        for i, row in enumerate(self.tetromino['shape']):
            for j, val in enumerate(row):
                if val == 1:
                    if x + j < 0 or x + j >= self.width or y + i < 0 or y + i >= self.height or self.grid[y + i][x + j] == 1:
                        return False
        return True

    def lock_tetromino(self):
        for i, row in enumerate(self.tetromino['shape']):
            for j, val in enumerate(row):
                if val == 1:
                    self.grid[self.tetromino['y'] + i][self.tetromino['x'] + j] = 1
        self.players[self.current_player].score += 1
        self.score += 1

    def clear_rows(self):
        rows_to_clear = []
        for i, row in enumerate(self.grid):
            if all(cell == 1 for cell in row):
                rows_to_clear.append(i)
        for row in rows_to_clear:
            del self.grid[row]
            self.grid.insert(0, [0 for _ in range(self.width)])
            self.score += 10
            self.players[self.current_player].score += 10

class Player:
    def __init__(self, id):
        self.id = id
        self.score = 0

