    def new_piece(self):
        return random.choice(["I", "J", "L", "O", "S", "T", "Z"])

    def rotate_piece(self, piece):
        if piece == "I":
            return "I"
        elif piece == "J":
            return "L"
        elif piece == "L":
            return "J"
        elif piece == "O":
            return "O"
        elif piece == "S":
            return "Z"
        elif piece == "T":
            return "T"
        elif piece == "Z":
            return "S"

    def check_collision(self, piece, x, y):
        if x < 0 or x >= self.width or y < 0 or y >= self.height:
            return True
        if self.grid[y][x] != 0:
            return True
        return False

    def place_piece(self, piece, x, y):
        if self.check_collision(piece, x, y):
            return False
        self.grid[y][x] = 1
        return True

    def clear_rows(self):
        rows_to_clear = []
        for i, row in enumerate(self.grid):
            if all(cell != 0 for cell in row):
                rows_to_clear.append(i)
        for row in rows_to_clear:
            self.grid.pop(row)
            self.grid.insert(0, [0 for _ in range(self.width)])
        return len(rows_to_clear)

    def update_score(self, rows_cleared):
        self.player_scores[self.players[self.player_turn]] += rows_cleared * rows_cleared
        self.player_turn = (self.player_turn + 1) % 3

