        if piece.y + dy < 0 or piece.y + dy + piece.height > self.height:
            return False
        for i in range(piece.height):
            for j in range(piece.width):
                if piece.shape[i][j] == 1 and self.grid[piece.y + dy + i][piece.x + dx + j] == 1:
                    return False
        piece.x += dx
        piece.y += dy
        return True

    def drop_piece(self, piece):
        while self.move_piece(piece, 0, 1):
            pass

    def check_collision(self, piece):
        for i in range(piece.height):
            for j in range(piece.width):
                if piece.shape[i][j] == 1 and (piece.y + i >= self.height or self.grid[piece.y + i][piece.x + j] == 1):
                    return True
        return False

    def remove_row(self, row):
        del self.grid[row]
        self.grid.insert(0, [0 for _ in range(self.width)])

    def update_score(self, player, score):
        self.players[player-1].score += score

    def get_score(self, player):
        return self.players[player-1].score

class Player:
