        self.id = id
        self.score = 0

class Piece:
    def __init__(self, type):
        self.type = type
        self.shape = []
        self.x = 0
        self.y = 0
        self.width = 0
        self.height = 0
        self.init_shape()

    def init_shape(self):
        if self.type == 0:
            self.shape = [[1, 1, 1, 1]]
            self.width = 4
            self.height = 1
        elif self.type == 1:
            self.shape = [[1, 1], [1, 1]]
            self.width = 2
            self.height = 2
        elif self.type == 2:
            self.shape = [[1, 1, 1], [0, 1, 0]]
            self.width = 3
            self.height = 2
        elif self.type == 3:
            self.shape = [[0, 1, 1], [1, 1, 0]]
            self.width = 3
            self.height = 2
        elif self.type == 4:
            self.shape = [[1, 1, 0], [0, 1, 1]]
            self.width = 3
            self.height = 2
        elif self.type == 5:
            self.shape = [[0, 1, 0], [1, 1, 1]]
            self.width = 3
            self.height = 2
        elif self.type == 6:
            self.shape = [[1, 0, 0], [1, 1, 1]]
            self.width = 3
            self.height = 2

    def rotate(self):
        new_shape = [[0 for _ in range(self.height)] for _ in range(self.width)]
        for i in range(self.height):
            for j in range(self.width):
                new_shape[j][self.height - i - 1] = self.shape[i][j]
        self.shape = new_shape
        self.width, self.height = self.height, self.width
        return self

