        self.score += points

def draw_text(text, font, color, surface, x, y):
    text_obj = font.render(text, 1, color)
    text_rect = text_obj.get_rect()
    text_rect.topleft = (x, y)
    surface.blit(text_obj, text_rect)

def main():
    pygame.init()
    clock = pygame.time.Clock()
    font = pygame.font.SysFont('Arial', 24)
    screen = pygame.display.set_mode((800, 600))
    tetris = Tetris()
    piece = tetris.get_new_piece()
    x, y = 5, 0
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    if not tetris.check_collision(piece, x - 1, y):
                        x -= 1
                elif event.key == pygame.K_RIGHT:
                    if not tetris.check_collision(piece, x + 1, y):
                        x += 1
                elif event.key == pygame.K_DOWN:
                    if not tetris.check_collision(piece, x, y + 1):
                        y += 1
                elif event.key == pygame.K_UP:
                    piece = tetris.rotate(piece)
                    if tetris.check_collision(piece, x, y):
                        piece = tetris.rotate(tetris.rotate(tetris.rotate(piece)))
                elif event.key == pygame.K_SPACE:
                    while not tetris.check_collision(piece, x, y + 1):
                        y += 1
                    tetris.update_grid(piece, x, y)
                    for i, row in enumerate(tetris.grid):
                        if all(row):
                            tetris.remove_row(i)
                            tetris.players[tetris.current_player].update_score(100)
                            tetris.score += 100
                    tetris.current_player = (tetris.current_player + 1) % 3
                    piece = tetris.get_new_piece()
                    x, y = 5, 0
        screen.fill((0, 0, 0))
        for i, row in enumerate(tetris.grid):
            for j, val in enumerate(row):
                if val:
                    pygame.draw.rect(screen, (255, 255, 255), (j * 30 + 100, i * 30 + 100, 30, 30), 0)
        for i, row in enumerate(piece):
            for j, val in enumerate(row):
                if val:
                    pygame.draw.rect(screen, (255, 0, 0), ((x + j) * 30 + 100, (y + i) * 30 + 100, 30, 30), 0)
        draw_text(f'Score: {tetris.score}', font, (255, 255, 255), screen, 10, 10)
        draw_text(f'Player {tetris.current_player + 1} turn', font, (255, 255, 255), screen, 10, 40)
        draw_text(f'Player 1 score: {tetris.players[0].score}', font, (255, 255, 255), screen, 10, 70)
        draw_text(f'Player 2 score: {tetris.players[1].score}', font, (255, 255, 255), screen, 10, 100)
        draw_text(f'Player 3 score: {tetris.players[2].score}', font, (255, 255, 255), screen, 10, 130)
        pygame.display.flip()
        clock.tick(60)
    pygame.quit()

if __name__ == '__main__':
    main()
